// Caso: FizzBuzz | Nivel: Básico | Categoría: Clásicos
#include <stdlib.h>
#include <stdio.h>
#include <string.h>
/* Retorna array de strings (malloc). Caller libera cada string y el array. */
char** solve(int n){
  char** out=(char**)malloc(sizeof(char*)*n);
  for(int i=1;i<=n;i++){
    char buf[16]; buf[0]=0;
    if(i%3==0) strcat(buf,"Fizz");
    if(i%5==0) strcat(buf,"Buzz");
