// Caso: Validar brackets (clásico) | Nivel: Intermedio | Categoría: Clásicos
#include <stdbool.h>
#include <string.h>
bool solve(const char* s){
  char st[2048]; int top=0;
  for(int i=0;s[i];i++){
    char ch=s[i];
    if(ch=='('||ch=='['||ch=='{') st[top++]=ch;
    else if(ch==')'||ch==']'||ch=='}'){
      if(top==0) return false;
      char o=st[--top];
      if((o=='('&&ch!=')')||(o=='['&&ch!=']')||(o=='{'&&ch!='}')) return false;
    }
  }
  return top==0;
}

