// Caso: Validar RUT chileno | Nivel: Intermedio | Categoría: Validación
#include <ctype.h>
#include <string.h>

int solve(const char* rut){
  if(!rut) return 0;

  char clean[64];
  int n=0;
  for(int i=0; rut[i] && n < 63; i++){
    char c = rut[i];
    if(c=='.' || c=='-' || isspace((unsigned char)c)) continue;
    clean[n++] = (char)toupper((unsigned char)c);
  }
  clean[n]='\0';
  if(n < 2) return 0;

  char dv = clean[n-1];
  clean[n-1] = '\0'; // body

  for(int i=0; clean[i]; i++){
    if(!isdigit((unsigned char)clean[i])) return 0;
  }

  int sum=0, mul=2;
  for(int i=(int)strlen(clean)-1; i>=0; i--){
    int d = clean[i]-'0';
    sum += d * mul;
    mul = (mul==7)?2:(mul+1);
  }

  int mod = 11 - (sum % 11);
  char dvCalc = (mod==11)?'0':(mod==10)?'K':(char)('0'+mod);
  return dv==dvCalc;
}

snippets.C0650:
// C0650 · Leer/Escribir CSV (UTF-8) (Intermedio, IO)
/*
  CSV simple (sin comillas/escapes complejos): lee input.csv, baja a lower-case columna "Email".
  Para CSV real con comillas, usa una librería (p.ej. libcsv).
*/
#include <stdio.h>
#include <string.h>
#include <ctype.h>

static void tolower_inplace(char *s){
  for(; *s; s++) *s = (char)tolower((unsigned char)*s);
}

int solve(void){
  FILE *in = fopen("input.csv","r");
  FILE *out = fopen("output.csv","w");
  if(!in || !out) return 1;

  char line[4096];
  if(!fgets(line, sizeof(line), in)) return 2;
  fputs(line, out);

  // detect Email column index (very naive: split by commas)
  int emailIdx = -1;
  int idx = 0;
  char header[4096];
  strcpy(header, line);
  char *tok = strtok(header, ",
");
  while(tok){
    if(strcmp(tok, "Email") == 0) emailIdx = idx;
    idx++;
    tok = strtok(NULL, ",
");
  }

  while(fgets(line, sizeof(line), in)){
    // naive split into fields
    char tmp[4096];
    strcpy(tmp, line);
    char *fields[128];
    int n=0;
    char *t = strtok(tmp, ",
");
    while(t && n<128){ fields[n++] = t; t = strtok(NULL, ",
"); }
    if(emailIdx >=0 && emailIdx < n) tolower_inplace(fields[emailIdx]);

    // re-write
    for(int i=0;i<n;i++){
      fputs(fields[i], out);
      fputc((i==n-1)?'
':',', out);
    }
  }

  fclose(in); fclose(out);
  return 0;
}

