// C0651 · Consumir API HTTP (GET y POST JSON) (Intermedio, HTTP)
/*
  C: HTTP típico con libcurl.
  - sudo apt-get install libcurl4-openssl-dev
  - gcc file.c -lcurl
*/
#include <curl/curl.h>
#include <stdlib.h>
#include <string.h>

struct Buf { char *p; size_t n; };

static size_t write_cb(char *ptr, size_t size, size_t nmemb, void *userdata){
  size_t total = size * nmemb;
  struct Buf *b = (struct Buf*)userdata;
  char *np = (char*)realloc(b->p, b->n + total + 1);
  if(!np) return 0;
  b->p = np;
  memcpy(b->p + b->n, ptr, total);
  b->n += total;
  b->p[b->n] = 0;
  return total;
}

int solve(){
  CURL *curl = curl_easy_init();
  if(!curl) return 1;

  struct Buf get = {0}, post = {0};

  curl_easy_setopt(curl, CURLOPT_URL, "https://httpbin.org/get");
  curl_easy_setopt(curl, CURLOPT_WRITEFUNCTION, write_cb);
  curl_easy_setopt(curl, CURLOPT_WRITEDATA, &get);
  curl_easy_setopt(curl, CURLOPT_TIMEOUT, 10L);
  if(curl_easy_perform(curl) != CURLE_OK) return 2;

  struct curl_slist *hdrs = NULL;
  hdrs = curl_slist_append(hdrs, "Content-Type: application/json");
  curl_easy_setopt(curl, CURLOPT_URL, "https://httpbin.org/post");
  curl_easy_setopt(curl, CURLOPT_HTTPHEADER, hdrs);
  curl_easy_setopt(curl, CURLOPT_POST, 1L);
  curl_easy_setopt(curl, CURLOPT_POSTFIELDS, "{"hello":"world"}");
  curl_easy_setopt(curl, CURLOPT_WRITEDATA, &post);
  if(curl_easy_perform(curl) != CURLE_OK) return 3;

  // Nota: aquí "get.p" y "post.p" contienen JSON texto. Parsear requiere lib JSON (cJSON, jansson).
  free(get.p); free(post.p);
  curl_slist_free_all(hdrs);
  curl_easy_cleanup(curl);
  return 0;
}

